    const N = nums.length;
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);

    /**
     * Generates a map where keys are XOR sums and values are the maximum subset size
     * that results in that XOR sum for the given array segment.
     * @param {number[]} arr - The array segment.
     * @returns {Map<number, number>} Map<XOR_sum, Max_Size>
     */
    const generateXorMap = (arr) => {
        const L = arr.length;
        // Map stores XOR_sum -> max_size
        const map = new Map();

        // Iterate through all 2^L subsets using bitmasks
        for (let i = 0; i < (1 << L); i++) {
            let currentXor = 0;
            let currentSize = 0;

            for (let j = 0; j < L; j++) {
                if ((i >> j) & 1) {
                    currentXor ^= arr[j];
                    currentSize++;
                }
            }

            if (!map.has(currentXor) || currentSize > map.get(currentXor)) {
                map.set(currentXor, currentSize);
            }
        }
        return map;
    };

    // 1. Generate maps for both halves
    const mapA = generateXorMap(A);
    const mapB = generateXorMap(B);

    let maxSize = -1;

    // 2. Combine results
    // Iterate over all possible results from A
    for (const [xorA, sizeA] of mapA.entries()) {
        // We need xorA ^ xorB = target, so xorB = target ^ xorA
        const xorBNeeded = target ^ xorA;

        if (mapB.has(xorBNeeded)) {
            const sizeB = mapB.get(xorBNeeded);
            const totalSize = sizeA + sizeB;

            if (totalSize > maxSize) {
                maxSize = totalSize;
            }
        }
    }

    // 3. Calculate minimum removals
    if (maxSize === -1) {
        return -1;
